AND (${whereSql})

SELECT T.RKRQ,SUM(T.YBTSE) YBTSE FROM GH_JF T  WHERE (#{rkrqStart} <= T.RKRQ and  T.RKRQ <= #{rkrqEnd})

    AND T.SPUUID = #{spuuid}

GROUP BY T.RKRQ
